select (select v_1 from (select sum(v_2 * (1 - v_3)) as v_1 from (select * from (select * from (select * from (select "l_orderkey" as v_4, "l_partkey" as v_5, "l_suppkey" as v_6, "l_linenumber" as v_7, "l_quantity" as v_8, "l_extendedprice" as v_2, "l_discount" as v_3, "l_tax" as v_9, "l_returnflag" as v_10, "l_linestatus" as v_11, "l_shipdate" as v_12, "l_commitdate" as v_13, "l_receiptdate" as v_14, "l_shipinstruct" as v_15, "l_shipmode" as v_16, "l_comment" as v_17 from "lineitem") s where (v_16 in ('AIR', 'AIR REG')) and (v_15 = 'DELIVER IN PERSON')) l inner join (select "p_partkey" as v_18, "p_name" as v_19, "p_mfgr" as v_20, "p_brand" as v_21, "p_type" as v_22, "p_size" as v_23, "p_container" as v_24, "p_retailprice" as v_25, "p_comment" as v_26 from "part") r on v_18 = v_5) s where (((((v_21 = 'Brand#12') and (v_24 in ('SM CASE', 'SM BOX', 'SM PACK', 'SM PKG'))) and (v_8 between 1 and (1 + 10))) and (v_23 between 1 and 5)) or ((((v_21 = 'Brand#23') and (v_24 in ('MED BAG', 'MED BOX', 'MED PKG', 'MED PACK'))) and (v_8 between 10 and (10 + 10))) and (v_23 between 1 and 10))) or ((((v_21 = 'Brand#34') and (v_24 in ('LG CASE', 'LG BOX', 'LG PACK', 'LG PKG'))) and (v_8 between 20 and (20 + 10))) and (v_23 between 1 and 15))) s) s)
